using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations ---------------------------------------------------

/// <summary>Provides web-search and note-taking tools for the research agent.</summary>
static class ResearchTools
{
    private static readonly List<string> _notes = [];
    private static readonly HttpClient _http = new();

    [Description("Search the web for a query and return a list of result snippets. Use this to gather information on a topic.")]
    public static async Task<string> WebSearch(
        [Description("The search query")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");
        Console.ResetColor();

        try
        {
            // Use Wikipedia's public search API – no key required.
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=5&format=json&utf8=1";
            var json = await _http.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var results = doc.RootElement
                .GetProperty("query")
                .GetProperty("search")
                .EnumerateArray()
                .Select(r =>
                {
                    var title = r.GetProperty("title").GetString();
                    // Strip HTML tags from the snippet
                    var snippet = System.Text.RegularExpressions.Regex.Replace(
                        r.GetProperty("snippet").GetString() ?? "", "<.*?>", "");
                    return $"• {title}: {snippet}";
                });

            var output = string.Join("\n", results);
            return string.IsNullOrWhiteSpace(output)
                ? "No results found."
                : output;
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record key findings as you research.")]
    public static string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved (#{_notes.Count})");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

// --- Agent loop --------------------------------------------------------------

var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    Console.ResetColor();
    return 1;
}

// Build the chat client with automatic function-calling support.
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(ResearchTools.WebSearch),
    AIFunctionFactory.Create(ResearchTools.SaveNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔬 AI Research Agent 🔬          ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic and the agent will        ║");
Console.WriteLine("║  search the web, take notes, and         ║");
Console.WriteLine("║  produce a summary.                      ║");
Console.WriteLine("║  Type 'quit' to exit.                    ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.ResetColor();

while (true)
{
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    var systemPrompt = """
        You are a research agent. Your job is to thoroughly research a topic and produce a well-structured summary.

        Follow these steps:
        1. Search the web 2-3 times with different queries to gather broad information.
        2. Save important findings as notes using the SaveNote tool.
        3. Once you have gathered enough material, retrieve your notes with GetNotes.
        4. Produce a final, well-organized summary with sections and key takeaways.

        Be thorough but concise. Cite sources when possible.
        """;

    List<ChatMessage> messages =
    [
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary:\n\n{topic}"),
    ];

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\nResearching \"{topic}\"...\n");
    Console.ResetColor();

    var response = await client.GetResponseAsync(messages, chatOptions);

    Console.ForegroundColor = ConsoleColor.White;
    Console.WriteLine("\n── Research Summary ─────────────────────────");
    Console.ResetColor();
    Console.WriteLine(response.Text);
    Console.WriteLine("─────────────────────────────────────────────");
}

Console.WriteLine("Goodbye!");
return 0;

