+/// <summary>Provides web-search and note-taking tools for the research agent.</summary>
+static class ResearchTools
+{
+    private static readonly List<string> _notes = [];
+    private static readonly HttpClient _http = new();
+
+    [Description("Search the web for a query and return a list of result snippets. Use this to gather information on a topic.")]
+    public static async Task<string> WebSearch(
+        [Description("The search query")] string query)
+    {
+        Console.ForegroundColor = ConsoleColor.DarkCyan;
+        Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");
+        Console.ResetColor();
+
+        try
+        {
+            // Use Wikipedia's public search API – no key required.
+            var encoded = Uri.EscapeDataString(query);
+            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=5&format=json&utf8=1";
+            var json = await _http.GetStringAsync(url);
+
+            using var doc = JsonDocument.Parse(json);
+            var results = doc.RootElement
+                .GetProperty("query")
+                .GetProperty("search")
+                .EnumerateArray()
+                .Select(r =>
+                {
+                    var title = r.GetProperty("title").GetString();
+                    var snippet = System.Text.RegularExpressions.Regex.Replace(
+                        r.GetProperty("snippet").GetString() ?? "", "<.*?>", "");
+                    return $"• {title}: {snippet}";
+                });
+
+            var output = string.Join("\n", results);
+            return string.IsNullOrWhiteSpace(output)
+                ? "No results found."
+                : output;
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}";
+        }
+    }
+
+    [Description("Save a research note. Use this to record key findings as you research.")]
+    public static string SaveNote(
+        [Description("The note text to save")] string note)
+    {
+        _notes.Add(note);
+        Console.ForegroundColor = ConsoleColor.DarkYellow;
+        Console.WriteLine($"  📝 Note saved (#{_notes.Count})");
+        Console.ResetColor();
+        return $"Note #{_notes.Count} saved.";
+    }
+
+    [Description("Retrieve all saved research notes.")]
+    public static string GetNotes()
+    {
+        if (_notes.Count == 0)
+            return "No notes saved yet.";
+
+        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
+    }
+}

